local function GetSpawnTime(self) return self.dycSpawnTime end local function SetSpawnTime(self, t) self.dycSpawnTime = GetTime() + (t or 0x0) end local function GetNextSpawnTime(self, ...) local retVal = self.dycOldGetNextSpawnTime and self.dycOldGetNextSpawnTime(self, ...) SetSpawnTime(self, retVal) return retVal end local function OnLoad(self, data, ...) local retVal = self.dycOldOnLoad and self.dycOldOnLoad(self, data, ...) if self.nexttime then SetSpawnTime(self, self.nexttime) end return retVal end local function LongUpdate(self, dt, ...) local retVal = self.dycOldLongUpdate and self.dycOldLongUpdate(self, dt, ...) local spawnTime = GetSpawnTime(self) if spawnTime then SetSpawnTime(self, spawnTime - GetTime() - dt) end return retVal end local function DYCRocManager(self) self.dycOldGetNextSpawnTime = self.GetNextSpawnTime self.GetNextSpawnTime = GetNextSpawnTime self.dycOldOnLoad = self.OnLoad self.OnLoad = OnLoad self.dycOldLongUpdate = self.LongUpdate self.LongUpdate = LongUpdate end return DYCRocManager 